const body = $input.first().json.body || $input.first().json;
const client = body.client || {};
const messages = body.messages || [];
const followUps = body.followUps || [];
const businessContext = body.businessContext || 'A solo service provider';

const recentMessages = messages.slice(0, 5).map(m => `- [${m.direction}] ${m.message_type}: ${m.summary || m.message}`).join('\n');
const pendingFollowUps = followUps.filter(f => f.status !== 'Completed').map(f => `- ${f.title} (due ${f.due_date})`).join('\n');

const prompt = `You are writing a personalised outreach message on behalf of a service provider.

About the sender's business:
${businessContext}

Client you are reaching out to:
- Name: ${client.name}
- Business type: ${client.business_type || 'Not specified'}
- Tags: ${(client.tags || []).join(', ') || 'None'}
- Status: ${client.status}
- Notes: ${client.notes || 'None'}
- Last contacted: ${client.last_contact_date || 'Not recently'}

Recent conversation history:
${recentMessages || 'No previous conversations'}

Pending follow-ups:
${pendingFollowUps || 'None'}

Write a WhatsApp message from the sender to this client. The message must:
1. Feel like it was written by a real person, not a template
2. Reference something specific about this client (their notes, business type, or last conversation)
3. Have a clear but soft call-to-action
4. Be under 120 words
5. Match the sender's business context — the language and offer should make sense for what they do

Return ONLY the message text. No subject line, no formatting, no quotation marks.`;

return [{ json: { prompt, client_name: client.name } }];

const draft = $input.first().json.message?.content || $input.first().json.content || '';
return [{
  json: {
    draft_text: draft.trim(),
    channel: 'WhatsApp',
    status: 'Draft'
  }
}];
